const { createHash, randomUUID } = require('crypto');

const UUID_PATTERN = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;

function uuidFromString(input) {
  const hash = createHash('sha1').update(String(input)).digest();
  hash[6] = (hash[6] & 0x0f) | 0x50;
  hash[8] = (hash[8] & 0x3f) | 0x80;
  const hex = hash.toString('hex');
  return `${hex.slice(0, 8)}-${hex.slice(8, 12)}-${hex.slice(12, 16)}-${hex.slice(16, 20)}-${hex.slice(20, 32)}`;
}

function ensureUuid(candidate, fallbackSeed) {
  if (typeof candidate === 'string') {
    const normalized = candidate.trim();
    if (UUID_PATTERN.test(normalized)) {
      return normalized.toLowerCase();
    }
    if (normalized.length > 0) {
      return uuidFromString(normalized);
    }
  }
  const seed = fallbackSeed ?? randomUUID();
  return uuidFromString(seed);
}

function safeNodeData(name) {
  try {
    const handle = $(name);
    if (!handle) {
      return null;
    }
    if (typeof handle.first === 'function') {
      const firstItem = handle.first();
      return firstItem?.json ?? null;
    }
    return handle.item?.json ?? null;
  } catch (error) {
    return null;
  }
}

function firstNonEmpty(...values) {
  for (const value of values) {
    if (typeof value === 'string' && value.trim().length > 0) {
      return value.trim();
    }
  }
  return '';
}

const telegramMessage = safeNodeData('Telegram Message Trigger')?.message ?? null;
const chatEvent = safeNodeData('When chat message received') ?? null;
const input = $json ?? {};

let text = firstNonEmpty(input.text, input.messageText, input.message);
let platform = input.platform ?? null;
let messageType = input.messageType ?? null;
let chatId = input.chatId ?? null;
let messageId = input.telegramMessageId ?? null;
let userId = input.userId ?? null;

if (!platform && telegramMessage) {
  platform = 'telegram';
}

if (!chatId && telegramMessage?.chat?.id != null) {
  chatId = String(telegramMessage.chat.id);
}

if (!messageId && telegramMessage?.message_id != null) {
  messageId = String(telegramMessage.message_id);
}

if (!text) {
  text = firstNonEmpty(
    telegramMessage?.text,
    telegramMessage?.caption,
    chatEvent?.text,
    chatEvent?.message,
    chatEvent?.query,
    input.rawText,
  );
}

if (!messageType) {
  messageType = telegramMessage?.voice || input.voiceTranscription === true ? 'voice' : 'text';
}

if (!platform) {
  platform = chatEvent ? 'n8n.chat' : 'unknown';
}

if (!userId) {
  if (platform === 'telegram' && telegramMessage?.from?.id != null) {
    userId = `telegram:${telegramMessage.from.id}`;
  } else if (chatEvent?.userId) {
    userId = String(chatEvent.userId);
  } else if (chatEvent?.sessionId) {
    userId = `n8n:${chatEvent.sessionId}`;
  } else if (chatId) {
    userId = `${platform}:${chatId}`;
  } else {
    userId = 'anonymous';
  }
}

const attachments = [];
if (telegramMessage?.voice) {
  attachments.push({
    type: 'telegram_voice',
    fileId: telegramMessage.voice.file_id,
    duration: telegramMessage.voice.duration ?? null,
  });
}

const timestamp = new Date().toISOString();
const personaId = 'chat';
const projectId = 'aismr';
const personaSlug = 'chat';
const projectSlug = 'aismr';

let sessionId = input.sessionId ?? null;
if (!sessionId && chatEvent?.sessionId) {
  sessionId = String(chatEvent.sessionId);
}
if (!sessionId) {
  if (platform === 'telegram' && chatId) {
    sessionId = `telegram:${chatId}`;
  } else if (chatId) {
    sessionId = `${platform}:${chatId}`;
  } else if (messageId) {
    sessionId = `${platform}:${messageId}`;
  }
}

sessionId = ensureUuid(sessionId, `${platform ?? 'unknown'}:${chatId ?? messageId ?? timestamp}`);

const messageText = text.trim();
const contentForStore = messageText.length > 0 ? messageText : '(empty message)';
const memoryQuery = messageText.length > 0
  ? messageText
  : messageType === 'voice'
    ? 'recent voice message transcription'
    : 'recent chat context';

const metadata = {
  platform,
  messageType,
  chatId: chatId ?? null,
  messageId,
  personaId,
  projectId,
  workflow: 'chat',
  timestamp,
};

if (attachments.length > 0) {
  metadata.attachments = attachments;
}

const conversationStorePayload = {
  sessionId,
  role: 'user',
  content: contentForStore,
  userId,
  metadata,
};

if (messageText.length > 0) {
  conversationStorePayload.embeddingText = messageText;
}

return {
  json: {
    platform,
    messageType,
    messageText,
    memoryQuery,
    chatId: chatId ? String(chatId) : null,
    messageId,
    userId,
    sessionId,
    timestamp,
    personaId,
    personaSlug,
    projectId,
    projectSlug,
    attachments,
    telegram: telegramMessage,
    rawInput: input,
    conversationStorePayload,
  },
};

// Simplified Assemble Agent Context - trust the AI to use MCP tools
// No pre-fetching - just give clear instructions

const base = $('Normalize Chat Event').item?.json ?? {};
const storeResponse = $('Store User Turn').item?.json ?? {};
const searchResponse = $('Search Memory').item?.json ?? {};
const recallResponse = $('Recall Conversation').item?.json ?? {};

const storedTurn = storeResponse.data?.turn ?? null;
const matches = Array.isArray(searchResponse.data?.matches) ? searchResponse.data.matches : [];
const recallTurns = Array.isArray(recallResponse.data?.turns) ? recallResponse.data.turns : [];

// Sort and prepare conversation context
const sortedTurns = [...recallTurns].sort((a, b) => (a.turnIndex ?? 0) - (b.turnIndex ?? 0));
const recentSlice = sortedTurns.slice(-10);
const recentContext = recentSlice
  .map((turn) => {
    const role = (turn.role ?? 'unknown').toUpperCase();
    const preview = String(turn.content ?? '')
      .replace(/\s+/g, ' ')
      .slice(0, 280);
    return `${role}: ${preview}`;
  })
  .join('\n');

// Summarize matches by type
function summarizeMatches(targetType) {
  return matches
    .filter((match) => {
      const types = match.metadata?.type ? [match.metadata.type] : [];
      const persona = match.metadata?.persona ?? [];
      const project = match.metadata?.project ?? [];
      if (targetType === 'persona') {
        return persona.length > 0;
      }
      if (targetType === 'project') {
        return project.length > 0;
      }
      return types.includes(targetType);
    })
    .slice(0, 3)
    .map((match, index) => {
      const title = match.metadata?.title ?? match.promptKey ?? `Match ${index + 1}`;
      const similarity =
        typeof match.similarity === 'number' ? `${(match.similarity * 100).toFixed(1)}%` : 'n/a';
      const preview = String(match.chunkText ?? '')
        .replace(/\s+/g, ' ')
        .trim()
        .slice(0, 320);
      return `#${index + 1} (${similarity}) ${title}: ${preview}`;
    })
    .join('\n');
}

const personaSummary = summarizeMatches('persona');

const proceduralSummary = matches
  .filter((match) => match.metadata?.type === 'workflow' || match.metadata?.type === 'instructions')
  .slice(0, 3)
  .map((match, index) => {
    const title = match.metadata?.title ?? match.promptKey ?? `Procedure ${index + 1}`;
    const preview = String(match.chunkText ?? '')
      .replace(/\s+/g, ' ')
      .trim()
      .slice(0, 320);
    return `• ${title}: ${preview}`;
  })
  .join('\n');

// Build system prompt with clear tool instructions
const systemSections = [];

systemSections.push(
  'You are Casey, an AI collaborator for Mylo. Answer succinctly, stay warm, and surface relevant tools or workflows.',
);

systemSections.push(
  '## IMPORTANT: Run These Tools FIRST (Before Responding)\n' +
    'Before working on any user request, you MUST run these MCP tools to gather context:\n' +
    '1. **prompt_search** with query "project" and memoryType="project" and limit=100\n' +
    '   - This loads ALL available projects in the system\n' +
    '   - You need to know what projects exist before answering questions about them\n' +
    '2. **GET /api/runs** with params: limit=20, status="complete,running,failed"\n' +
    '   - This loads recent workflow runs across all projects\n' +
    '   - You need this context to answer "what did we do" or "status of X" questions\n' +
    "3. Only AFTER running these tools should you address the user's actual request\n" +
    '\n' +
    'Why this matters: Users expect you to know about all projects and recent activity without having to ask.',
);

systemSections.push(
  `## Persona Guidance\n${personaSummary || 'No persona memory retrieved; default to Casey baseline tone.'}`,
);

systemSections.push(
  proceduralSummary
    ? `## Procedural References\n${proceduralSummary}`
    : '## Procedural References\nNo procedural workflows retrieved. Use prompt_search or MCP tools to find relevant automations.',
);

systemSections.push(
  recentContext
    ? `## Recent Conversation\n${recentContext}`
    : '## Recent Conversation\nNo prior turns available for this session.',
);

systemSections.push(
  '## Response Rules\n' +
    '- REMEMBER: Run the initialization tools listed above FIRST before responding\n' +
    '- Use MCP tools proactively: prompt_search for personas/projects, HTTP requests for runs/videos\n' +
    '- Confirm assumptions before triggering long processes (especially AISMR video generation)\n' +
    '- Offer 1-3 actionable suggestions when helpful\n' +
    '- Cite which tool or memory snippet informed your response\n' +
    "- Be concise but warm - this is Mylo's creative assistant",
);

const systemPrompt = systemSections.join('\n\n');

return {
  json: {
    persona: {
      id: base.personaId,
      slug: base.personaSlug,
    },
    project: {
      id: base.projectId,
      slug: base.projectSlug,
    },
    session: {
      id: storedTurn?.sessionId ?? base.sessionId,
      originalId: base.sessionId,
      userId: base.userId,
    },
    message: {
      text: base.messageText,
      type: base.messageType,
      timestamp: base.timestamp,
      telegramChatId: base.chatId ?? null,
      telegramMessageId: base.messageId ?? null,
      platform: base.platform,
    },
    platform: base.platform,
    attachments: base.attachments ?? [],
    memory: {
      matches,
      personaSummary,
      proceduralSummary,
      recentTurns: recentSlice,
    },
    conversation: {
      userTurn: storedTurn,
      recall: recallTurns,
    },
    systemPrompt,
    telemetry: {
      userStore: storeResponse,
      memorySearch: searchResponse,
      recall: recallResponse,
    },
  },
};

const context = $('Assemble Agent Context').item?.json ?? {};
const rawOutput = $json.output ?? $json.result ?? $json.response ?? $json;
let content = typeof rawOutput === 'string' ? rawOutput : rawOutput?.output ?? null;
if (!content || typeof content !== 'string' || content.trim().length === 0) {
  content = JSON.stringify(rawOutput, null, 2);
}
const trimmed = content.length > 12000 ? `${content.slice(0, 11997)}...` : content;
const timestamp = new Date().toISOString();

const metadata = {
  platform: context.platform,
  personaId: context.persona?.id ?? null,
  projectId: context.project?.id ?? null,
  workflow: 'chat',
  timestamp,
};

if (context.message?.telegramChatId) {
  metadata.chatId = context.message.telegramChatId;
}
if (context.message?.telegramMessageId) {
  metadata.messageId = context.message.telegramMessageId;
}

const payload = {
  sessionId: context.session?.id,
  role: 'assistant',
  content: trimmed,
  userId: context.session?.userId ?? null,
  metadata,
  embeddingText: trimmed,
};

return {
  json: {
    ...context,
    agentOutput: trimmed,
    responseText: trimmed,
    conversationStorePayload: payload,
  },
};

const context = $('Prepare Assistant Store Request').item?.json ?? {};
const assistantStore = $json.data?.turn ?? null;

return {
  json: {
    responseText: context.responseText,
    persona: context.persona ?? null,
    project: context.project ?? null,
    session: context.session ?? null,
    message: context.message ?? null,
    platform: context.platform ?? null,
    conversation: {
      userTurn: context.conversation?.userTurn ?? null,
      assistantTurn: assistantStore,
    },
    telemetry: {
      assistantStore: $json,
    },
  },
};
